#graphql
  query ProductMetafieldDefinitionsForResourceLimitNamespace($namespace: String!, $first: Int!, $after: String) {
    metafieldDefinitions(ownerType: PRODUCT, namespace: $namespace, first: $first, after: $after) {
      nodes {
        id
        namespace
        key
        ownerType
      }
      pageInfo {
        hasNextPage
        endCursor
      }
    }
  }

